import base64, sys
PATH="index.html"; SENTINEL="PL_PRI_INLINEADD_V1"
EDITS=[
('dmFyIGN1clBpZD1udWxsLCBjdXJQcmk9bnVsbCwgc3ViUE09bnVsbDs=','dmFyIGN1clBpZD1udWxsLCBjdXJQcmk9bnVsbCwgc3ViUE09bnVsbDsKdmFyIHBkQWRkaW5nPWZhbHNlOw=='),
('aCs9JzxzcGFuIGNsYXNzPSJwZC1hZGRjaGlwIiBvbmNsaWNrPSJwZEFkZFBlcnNvbigpIj4nK1BEX0FERCsnIEFkZCBwZXJzb248L3NwYW4+JzsgcGUuaW5uZXJIVE1MPWg7IH0=',''),
('ZnVuY3Rpb24gcGRBZGRQZXJzb24oKXsgaWYoY3VyUGlkKSBvcGVuUmFpc2VQcmlvcml0eShjdXJQaWQpOyB9',''),
('ZnVuY3Rpb24gb3BlblByaW9yaXR5KGlkKXsKICBjdXJQaWQ9aWQ7IGN1clByaT1wcmlCeUlkKGlkKTs=','ZnVuY3Rpb24gb3BlblByaW9yaXR5KGlkKXsKICBwZEFkZGluZz1mYWxzZTsgY3VyUGlkPWlkOyBjdXJQcmk9cHJpQnlJZChpZCk7'),
('LnBkLWRlbDpob3ZlcntiYWNrZ3JvdW5kOiNmZGVjZWF9','')
]
s=open(PATH,encoding="utf-8").read()
if SENTINEL in s:
    print("Already applied — no change.")
else:
    for k,(ob,nb) in enumerate(EDITS):
        old=base64.b64decode(ob).decode("utf-8"); new=base64.b64decode(nb).decode("utf-8")
        n=s.count(old)
        if n!=1:
            sys.stderr.write("ABORT edit %d: anchor count=%d (expected 1)\n"%(k,n)); sys.exit(1)
        s=s.replace(old,new)
    open(PATH,"w",encoding="utf-8").write(s)
    print("Applied %s. New size: %d bytes."%(SENTINEL,len(s.encode("utf-8"))))
